<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Falling Sand</title>
<style>
*{box-sizing:border-box;margin:0;padding:0}
body{background:#0d1117;color:#cdd6f4;font-family:'Segoe UI',system-ui,sans-serif;display:flex;flex-direction:column;align-items:center;min-height:100vh;padding:20px 16px;gap:14px;user-select:none}
h1{font-size:1.2rem;font-weight:300;letter-spacing:.28em;color:#484f58;text-transform:uppercase}
#controls{display:flex;gap:8px;flex-wrap:wrap;justify-content:center;align-items:center}
button{border:2px solid transparent;border-radius:6px;cursor:pointer;font-size:12px;font-weight:700;letter-spacing:.08em;padding:9px 18px;text-transform:uppercase;transition:filter .12s,transform .08s,box-shadow .12s}
button:hover{filter:brightness(1.25);transform:translateY(-1px)}
button:active{transform:translateY(1px)}
button.active{box-shadow:0 0 0 3px #fff,0 0 18px rgba(255,255,255,.2)}
#mat-sand{background:#c89428;color:#120c00}
#mat-water{background:#1560c0;color:#c8e4ff}
#mat-wall{background:#4a5568;color:#cbd5e0}
#mat-acid{background:#16962e;color:#e0ffe0}
#mat-empty{background:#1a1f2e;color:#636d7e;border-color:#3a4250}
#clear{background:#8b1e2e;color:#ffd0d8;margin-left:8px}
#sand{cursor:crosshair;image-rendering:pixelated;image-rendering:crisp-edges;border:2px solid #21262d;border-radius:6px;box-shadow:0 12px 48px rgba(0,0,0,.75);display:block}
#hint{font-size:11px;color:#32383f;letter-spacing:.06em}
</style>
</head>
<body>
<h1>Falling Sand</h1>
<div id="controls">
  <button id="mat-sand">Sand</button>
  <button id="mat-water">Water</button>
  <button id="mat-wall">Wall</button>
  <button id="mat-acid">Acid</button>
  <button id="mat-empty">Erase</button>
  <button id="clear">Clear</button>
</div>
<canvas id="sand"></canvas>
<div id="hint">drag to paint &nbsp;·&nbsp; scroll to resize brush</div>
<script>
(function(){
'use strict';
const EMPTY=0,SAND=1,WATER=2,WALL=3,ACID=4;
const NAMES=['empty','sand','water','wall','acid'];
const IDS={empty:0,sand:1,water:2,wall:3,acid:4};
const W=120,H=120;
const grid=new Uint8Array(W*H);
const moved=new Uint8Array(W*H);

// Canvas: W×H logical pixels, displayed at 600×600 CSS px
const PX=600;
const cv=document.getElementById('sand');
cv.width=W; cv.height=H;
cv.style.width=PX+'px'; cv.style.height=PX+'px';
const ctx=cv.getContext('2d');
ctx.imageSmoothingEnabled=false;
const img=ctx.createImageData(W,H);
const pix=img.data;

// Base RGB per material
const RGB=[[13,17,23],[208,152,38],[22,96,196],[78,90,106],[30,195,66]];

// Helpers
const inB=(x,y)=>x>=0&&x<W&&y>=0&&y<H;
const G=(x,y)=>grid[y*W+x];
const Gs=(x,y,v)=>{grid[y*W+x]=v;};
const isLiq=t=>t===WATER||t===ACID;

function swap(x1,y1,x2,y2){
  const a=y1*W+x1,b=y2*W+x2,t=grid[a];
  grid[a]=grid[b]; grid[b]=t;
  moved[a]=1; moved[b]=1;
}

// Sand: falls down, displaces unmoved liquid, slides diagonal
function doSand(x,y){
  if(y<H-1){
    const b=G(x,y+1);
    if(b===EMPTY){swap(x,y,x,y+1);return;}
    // Only displace liquid if it hasn't already moved this tick (prevents anti-gravity)
    if(isLiq(b)&&!moved[(y+1)*W+x]){swap(x,y,x,y+1);return;}
  }
  const d=Math.random()<.5?[-1,1]:[1,-1];
  for(const dx of d){
    const nx=x+dx;
    if(nx<0||nx>=W||y>=H-1)continue;
    const b=G(nx,y+1);
    if(b===EMPTY){swap(x,y,nx,y+1);return;}
    if(isLiq(b)&&!moved[(y+1)*W+nx]){swap(x,y,nx,y+1);return;}
  }
}

// Water: falls, diagonal fall, horizontal spread
function doWater(x,y){
  if(y<H-1&&G(x,y+1)===EMPTY){swap(x,y,x,y+1);return;}
  const d=Math.random()<.5?[-1,1]:[1,-1];
  for(const dx of d){
    const nx=x+dx;
    if(nx>=0&&nx<W&&y<H-1&&G(nx,y+1)===EMPTY){swap(x,y,nx,y+1);return;}
  }
  const h=Math.random()<.5?[-1,1]:[1,-1];
  for(const dx of h){
    const nx=x+dx;
    if(nx>=0&&nx<W&&G(nx,y)===EMPTY){swap(x,y,nx,y);return;}
  }
}

// Acid: dissolve neighbors, then move like water
function doAcid(x,y){
  const nb=[[x,y+1],[x-1,y],[x+1,y],[x,y-1]];
  for(const[tx,ty]of nb){
    if(!inB(tx,ty))continue;
    const t=G(tx,ty);
    if((t===SAND||t===WALL)&&Math.random()<.04){
      Gs(tx,ty,EMPTY); moved[ty*W+tx]=1;
      if(Math.random()<.28){Gs(x,y,EMPTY);moved[y*W+x]=1;return;}
    }
  }
  if(y<H-1&&G(x,y+1)===EMPTY){swap(x,y,x,y+1);return;}
  const d=Math.random()<.5?[-1,1]:[1,-1];
  for(const dx of d){
    const nx=x+dx;
    if(nx>=0&&nx<W&&y<H-1&&G(nx,y+1)===EMPTY){swap(x,y,nx,y+1);return;}
  }
  const h=Math.random()<.5?[-1,1]:[1,-1];
  for(const dx of h){
    const nx=x+dx;
    if(nx>=0&&nx<W&&G(nx,y)===EMPTY){swap(x,y,nx,y);return;}
  }
}

function stepCell(x,y){
  const i=y*W+x;
  if(moved[i])return;
  switch(grid[i]){
    case SAND: doSand(x,y); break;
    case WATER: doWater(x,y); break;
    case ACID: doAcid(x,y); break;
  }
}

// tick: synchronous, bottom-row-up so each particle moves at most once per step
function tick(n){
  const steps=n|0;
  for(let s=0;s<steps;s++){
    moved.fill(0);
    for(let y=H-1;y>=0;y--){
      // Randomise x scan direction per row to prevent directional bias
      if(Math.random()<.5){
        for(let x=0;x<W;x++) stepCell(x,y);
      }else{
        for(let x=W-1;x>=0;x--) stepCell(x,y);
      }
    }
  }
}

function render(){
  let i=0,p=0;
  for(let y=0;y<H;y++){
    for(let x=0;x<W;x++,i++,p+=4){
      const m=grid[i];
      if(m===SAND){
        // subtle positional texture so grains look distinct
        const v=((x*73856093^y*19349663)>>>0)&31;
        pix[p]  =RGB[SAND][0]+(v>>1)-8;
        pix[p+1]=RGB[SAND][1]+(v&15)-6;
        pix[p+2]=RGB[SAND][2];
      }else if(m===WATER){
        const v=((x*2654435769^y*2246822519)>>>0)&15;
        pix[p]  =RGB[WATER][0];
        pix[p+1]=RGB[WATER][1]+(v>>1);
        pix[p+2]=RGB[WATER][2]+(v>>2);
      }else{
        const c=RGB[m];
        pix[p]=c[0]; pix[p+1]=c[1]; pix[p+2]=c[2];
      }
      pix[p+3]=255;
    }
  }
  ctx.putImageData(img,0,0);
}

// Public API
window.sim={
  w:W, h:H,
  tick(n){tick(n);},
  get(x,y){return inB(x,y)?NAMES[G(x,y)]:'empty';},
  set(x,y,mat){const id=IDS[mat];if(id!==undefined&&inB(x,y))Gs(x,y,id);},
  clear(){grid.fill(EMPTY);}
};

// UI
let curMat=SAND,brushR=3,painting=false;
const BMAP={'mat-sand':SAND,'mat-water':WATER,'mat-wall':WALL,'mat-acid':ACID,'mat-empty':EMPTY};

function choose(m){
  curMat=m;
  for(const[id,v]of Object.entries(BMAP))
    document.getElementById(id).classList.toggle('active',v===m);
}
for(const[id,v]of Object.entries(BMAP))
  document.getElementById(id).addEventListener('click',()=>choose(v));
document.getElementById('clear').addEventListener('click',()=>window.sim.clear());
choose(SAND);

function paintAt(cx,cy){
  const r=cv.getBoundingClientRect();
  const gx=Math.floor((cx-r.left)/r.width*W);
  const gy=Math.floor((cy-r.top)/r.height*H);
  const b=brushR;
  for(let dy=-b;dy<=b;dy++)
    for(let dx=-b;dx<=b;dx++)
      if(dx*dx+dy*dy<=b*b&&inB(gx+dx,gy+dy))
        Gs(gx+dx,gy+dy,curMat);
}

cv.addEventListener('mousedown',e=>{painting=true;paintAt(e.clientX,e.clientY);});
cv.addEventListener('mousemove',e=>{if(painting)paintAt(e.clientX,e.clientY);});
window.addEventListener('mouseup',()=>{painting=false;});
cv.addEventListener('contextmenu',e=>e.preventDefault());
cv.addEventListener('wheel',e=>{
  e.preventDefault();
  brushR=Math.max(1,Math.min(15,brushR+(e.deltaY<0?1:-1)));
},{passive:false});
cv.addEventListener('touchstart',e=>{e.preventDefault();painting=true;paintAt(e.touches[0].clientX,e.touches[0].clientY);},{passive:false});
cv.addEventListener('touchmove',e=>{e.preventDefault();if(painting)paintAt(e.touches[0].clientX,e.touches[0].clientY);},{passive:false});
cv.addEventListener('touchend',()=>{painting=false;});

// Animation loop
(function loop(){tick(1);render();requestAnimationFrame(loop);})();
})();
</script>
</body>
</html>
